//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagegameliftimport("context""fmt""log""time""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/gamelift""github.com/hashicorp/aws-sdk-go-base/v2/awsv1shim/v2/tfawserr""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry")const(buildReadyTimeout=1*time.Minute)funcwaitBuildReady(ctxcontext.Context,conn*gamelift.GameLift,idstring)(*gamelift.Build,error){stateConf:=&retry.StateChangeConf{Pending:[]string{gamelift.BuildStatusInitialized},Target:[]string{gamelift.BuildStatusReady},Refresh:statusBuild(ctx,conn,id),Timeout:buildReadyTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*gamelift.Build);ok{returnoutput,err}returnnil,err}funcwaitFleetActive(ctxcontext.Context,conn*gamelift.GameLift,idstring,timeouttime.Duration)(*gamelift.FleetAttributes,error){stateConf:=&retry.StateChangeConf{Pending:[]string{gamelift.FleetStatusActivating,gamelift.FleetStatusBuilding,gamelift.FleetStatusDownloading,gamelift.FleetStatusNew,gamelift.FleetStatusValidating,},Target:[]string{gamelift.FleetStatusActive},Refresh:statusFleet(ctx,conn,id),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*gamelift.FleetAttributes);ok{returnoutput,err}returnnil,err}funcwaitFleetTerminated(ctxcontext.Context,conn*gamelift.GameLift,idstring,timeouttime.Duration)(*gamelift.FleetAttributes,error){stateConf:=&retry.StateChangeConf{Pending:[]string{gamelift.FleetStatusActive,gamelift.FleetStatusDeleting,gamelift.FleetStatusError,gamelift.FleetStatusTerminated,},Target:[]string{},Refresh:statusFleet(ctx,conn,id),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)iferr!=nil{events,fErr:=getFleetFailures(ctx,conn,id)iffErr!=nil{log.Printf("[WARN]Failedtopollfleetfailures:%s",fErr)}iflen(events)>0{returnnil,fmt.Errorf("%sRecentfailures:\n%+v",err,events)}}ifoutput,ok:=outputRaw.(*gamelift.FleetAttributes);ok{returnoutput,err}returnnil,err}funcgetFleetFailures(ctxcontext.Context,conn*gamelift.GameLift,idstring)([]*gamelift.Event,error){varevents[]*gamelift.Eventerr:=_getFleetFailures(ctx,conn,id,nil,&events)returnevents,err}func_getFleetFailures(ctxcontext.Context,conn*gamelift.GameLift,idstring,nextToken*string,events*[]*gamelift.Event)error{eOut,err:=conn.DescribeFleetEventsWithContext(ctx,&gamelift.DescribeFleetEventsInput{FleetId:aws.String(id),NextToken:nextToken,})iferr!=nil{returnerr}for_,e:=rangeeOut.Events{ifisEventFailure(e){*events=append(*events,e)}}ifeOut.NextToken!=nil{err:=_getFleetFailures(ctx,conn,id,nextToken,events)iferr!=nil{returnerr}}returnnil}funcisEventFailure(event*gamelift.Event)bool{failureCodes:=[]string{gamelift.EventCodeFleetActivationFailed,gamelift.EventCodeFleetActivationFailedNoInstances,gamelift.EventCodeFleetBinaryDownloadFailed,gamelift.EventCodeFleetInitializationFailed,gamelift.EventCodeFleetStateError,gamelift.EventCodeFleetValidationExecutableRuntimeFailure,gamelift.EventCodeFleetValidationLaunchPathNotFound,gamelift.EventCodeFleetValidationTimedOut,gamelift.EventCodeFleetVpcPeeringFailed,gamelift.EventCodeGameSessionActivationTimeout,gamelift.EventCodeServerProcessCrashed,gamelift.EventCodeServerProcessForceTerminated,gamelift.EventCodeServerProcessInvalidPath,gamelift.EventCodeServerProcessProcessExitTimeout,gamelift.EventCodeServerProcessProcessReadyTimeout,gamelift.EventCodeServerProcessSdkInitializationTimeout,gamelift.EventCodeServerProcessTerminatedUnhealthy,}for_,fc:=rangefailureCodes{ifaws.StringValue(event.EventCode)==fc{returntrue}}returnfalse}funcwaitGameServerGroupActive(ctxcontext.Context,conn*gamelift.GameLift,namestring,timeouttime.Duration)(*gamelift.GameServerGroup,error){stateConf:=&retry.StateChangeConf{Pending:[]string{gamelift.GameServerGroupStatusNew,gamelift.GameServerGroupStatusActivating,},Target:[]string{gamelift.GameServerGroupStatusActive},Refresh:statusGameServerGroup(ctx,conn,name),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*gamelift.GameServerGroup);ok{returnoutput,err}returnnil,err}funcwaitGameServerGroupTerminated(ctxcontext.Context,conn*gamelift.GameLift,namestring,timeouttime.Duration)error{stateConf:=&retry.StateChangeConf{Pending:[]string{gamelift.GameServerGroupStatusDeleteScheduled,gamelift.GameServerGroupStatusDeleting,},Target:[]string{},Refresh:statusGameServerGroup(ctx,conn,name),Timeout:timeout,}_,err:=stateConf.WaitForStateContext(ctx)iftfawserr.ErrCodeEquals(err,gamelift.ErrCodeNotFoundException){returnnil}iferr!=nil{returnfmt.Errorf("deletingGameLiftGameServerGroup(%s):%w",name,err)}returnnil}